  void start_insn_deferred(uint64_t id)
  {
    inflight_.insert(id);
    *output_ << fmt::format("I\t{}\t{}\t0\n", id, id);
  }

  /// Back-fill label for a deferred instruction (OoO commit).
  void label_insn(uint64_t id, uint64_t pc,
                  std::string_view suffix = "")
  {
    if (!is_inflight(id))
      return;
    auto it = code_map_.find(pc);
    auto code = (it != code_map_.end()) ? it->second : std::string{};
    if (suffix.empty())
      *output_ << fmt::format("L\t{}\t0\t{:#x}: {}\n", id, pc, code);
    else
      *output_ << fmt::format("L\t{}\t0\t{:#x}: {} [{}]\n", id, pc, code,
                              suffix);
  }

  void retire_insn(uint64_t id)
  {
    if (remove_inflight(id))
      *output_ << fmt::format("R\t{}\t{}\t0\n", id, id);
  }

  void flush_insn(uint64_t id)
  {
    if (remove_inflight(id))
      *output_ << fmt::format("R\t{}\t0\t1\n", id);
  }

  void stage_insn(uint64_t id, std::string_view stage_name, int lane_id = 0)
  {
    if (is_inflight(id))
      *output_ << fmt::format("S\t{}\t{}\t{}\n", id, lane_id, stage_name);
  }

  void end_stage_insn(uint64_t id, std::string_view stage_name)
  {
    if (is_inflight(id))
      *output_ << fmt::format("E\t{}\t0\t{}\n", id, stage_name);
  }

  void comment_insn(uint64_t id, std::string_view msg)
  {
    if (is_inflight(id))
      *output_ << fmt::format("L\t{}\t1\t{}\n", id, msg);
  }

  void flush_all()
  {
    for (auto id: inflight_)
      *output_ << fmt::format("R\t{}\t0\t1\n", id);
    inflight_.clear();
    output_->flush();
  }

  /// Load objdump -d output to populate PC→assembly map.
  void load_objdump(const std::string& filename)
  {
    std::ifstream fin(filename);
    if (!fin.is_open()) {
      spdlog::warn("Failed to open objdump file: {}", filename);
      return;
    }
    std::regex code_regex(R"(^\s*([0-9a-f]+):\t([0-9a-f ]+)\t(.+)$)");
    std::string line;
    while (std::getline(fin, line)) {
      std::smatch match;
      if (std::regex_match(line, match, code_regex)) {
        auto pc = std::stoull(match[1].str(), nullptr, 16);
        auto asm_code = match[3].str();
        // Replace tabs with double spaces (same as Python)
        for (auto pos = asm_code.find('\t'); pos != std::string::npos;
             pos = asm_code.find('\t', pos))
