template<typename CPU>
std::unique_ptr<PipelineViewer<CPU>> make_kanata_viewer(
  CPU& cpu, const std::string& filename,
  const std::string& objdump_file = "")
{
  // Try OoO path first (AX66)
  if (kanata::is_ooo_cpu(cpu.modelName())) {
    int num_cores = kanata::ax66_ooo_num_cores(cpu);
    spdlog::info("Kanata: detected AX66 OoO pipeline ({} core{})",
                 num_cores, num_cores > 1 ? "s" : "");

    if (num_cores == 1) {
      // Single-core: one file, unchanged behavior
      auto logger = std::make_unique<kanata::KanataLogger>(filename);
      if (!logger->is_open())
        return nullptr;
      if (!objdump_file.empty())
        logger->load_objdump(objdump_file);
      auto config = kanata::make_ax66_ooo_config(cpu, 0);
      return std::make_unique<OoOKanataViewer<CPU>>(
        cpu, std::move(logger), std::move(config));
    }

    // Multi-core: split into per-core files
    namespace fs = std::filesystem;
    auto path = fs::path(filename);
    auto stem = path.stem().string();
    auto ext = path.extension().string();
    auto parent = path.parent_path();

    auto multi = std::make_unique<MultiCoreOoOKanataViewer<CPU>>();
    for (int core = 0; core < num_cores; ++core) {
      auto core_file =
        (parent / fmt::format("{}_core{}{}", stem, core, ext)).string();
      spdlog::info("Kanata: core {} -> {}", core, core_file);
      auto logger = std::make_unique<kanata::KanataLogger>(core_file);
      if (!logger->is_open())
        return nullptr;
      if (!objdump_file.empty())
        logger->load_objdump(objdump_file);
      auto config = kanata::make_ax66_ooo_config(cpu, core);
      multi->add(std::make_unique<OoOKanataViewer<CPU>>(
        cpu, std::move(logger), std::move(config)));
    }
    return multi;
  }

  // In-order path
  auto config = kanata::detect_config(cpu.modelName());
  if (!config)
    return nullptr;

  auto logger = std::make_unique<kanata::KanataLogger>(filename);
  if (!logger->is_open())
    return nullptr;

  if (!objdump_file.empty())
    logger->load_objdump(objdump_file);

  return std::make_unique<KanataViewer<CPU>>(cpu, std::move(logger),
                                             std::move(*config));
}

